import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Venue } from '../../core/models';

/**
 * GatherUp venues list (organizer). Loads live via ApiService.listVenues();
 * delete calls ApiService.deleteVenue().
 */
@Component({
  selector: 'app-venues-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './venues-list.component.html',
  styleUrl: './venues-list.component.css',
})
export class VenuesListComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly venues = signal<Venue[]>([]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.load();
  }

  private load(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.listVenues().subscribe({
      next: (venues) => {
        this.venues.set(venues);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load venues. Please try again.');
        this.loading.set(false);
      },
    });
  }

  remove(v: Venue): void {
    // Optimistically drop it, then confirm with the backend.
    this.venues.update((list) => list.filter((x) => x.id !== v.id));
    this.api.deleteVenue(v.id).subscribe({
      next: () => {},
      error: () => {
        this.error.set('Could not delete the venue. Refreshing the list.');
        this.load();
      },
    });
  }
}
